import { ethers } from "ethers";

const RPC_URL = process.env.RPC_URL || "https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID";
const PRIVATE_KEY = process.env.PRIVATE_KEY || "YOUR_PRIVATE_KEY";

if (!PRIVATE_KEY || PRIVATE_KEY === "YOUR_PRIVATE_KEY") {
  throw new Error("Missing PRIVATE_KEY environment variable");
}

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

export function getProvider() {
  return provider;
}

export function getWallet() {
  return wallet;
}

export async function getNativeBalance(address) {
  const balance = await provider.getBalance(address);
  return ethers.formatEther(balance);
}

export async function sendETH(to, amountInEth, options = {}) {
  const tx = await wallet.sendTransaction({
    to,
    value: ethers.parseEther(String(amountInEth)),
    gasLimit: options.gasLimit ? BigInt(options.gasLimit) : undefined,
    maxFeePerGas: options.maxFeePerGas ? ethers.parseUnits(String(options.maxFeePerGas), "gwei") : undefined,
    maxPriorityFeePerGas: options.maxPriorityFeePerGas
      ? ethers.parseUnits(String(options.maxPriorityFeePerGas), "gwei")
      : undefined,
    nonce: options.nonce,
  });

  const receipt = await tx.wait(options.confirmations || 1);

  return {
    hash: tx.hash,
    from: tx.from,
    to: tx.to,
    value: amountInEth,
    receipt,
  };
}

export function getContract(contractAddress, abi, signerOrProvider = wallet) {
  return new ethers.Contract(contractAddress, abi, signerOrProvider);
}

export async function callContractRead(contractAddress, abi, method, args = []) {
  const contract = getContract(contractAddress, abi, provider);
  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} not found on contract`);
  }
  return await contract[method](...args);
}

export async function sendContractTransaction(contractAddress, abi, method, args = [], options = {}) {
  const contract = getContract(contractAddress, abi, wallet);

  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} not found on contract`);
  }

  const overrides = {};
  if (options.value !== undefined) {
    overrides.value = ethers.parseEther(String(options.value));
  }
  if (options.gasLimit !== undefined) {
    overrides.gasLimit = BigInt(options.gasLimit);
  }
  if (options.maxFeePerGas !== undefined) {
    overrides.maxFeePerGas = ethers.parseUnits(String(options.maxFeePerGas), "gwei");
  }
  if (options.maxPriorityFeePerGas !== undefined) {
    overrides.maxPriorityFeePerGas = ethers.parseUnits(String(options.maxPriorityFeePerGas), "gwei");
  }
  if (options.nonce !== undefined) {
    overrides.nonce = options.nonce;
  }

  const tx = await contract[method](...args, overrides);
  const receipt = await tx.wait(options.confirmations || 1);

  return {
    hash: tx.hash,
    receipt,
  };
}

export async function estimateEthTransferGas(to, amountInEth) {
  return await provider.estimateGas({
    from: wallet.address,
    to,
    value: ethers.parseEther(String(amountInEth)),
  });
}

export async function estimateContractGas(contractAddress, abi, method, args = [], options = {}) {
  const contract = getContract(contractAddress, abi, wallet);

  if (!contract[method] || !contract[method].estimateGas) {
    throw new Error(`Method ${method} not found or gas estimation unavailable`);
  }

  const overrides = {};
  if (options.value !== undefined) {
    overrides.value = ethers.parseEther(String(options.value));
  }

  return await contract[method].estimateGas(...args, overrides);
}

export async function getTransaction(txHash) {
  return await provider.getTransaction(txHash);
}

export async function getTransactionReceipt(txHash) {
  return await provider.getTransactionReceipt(txHash);
}

export async function getCurrentBlockNumber() {
  return await provider.getBlockNumber();
}

export async function getNetwork() {
  return await provider.getNetwork();
}

export async function waitForTransaction(txHash, confirmations = 1, timeout = 120000) {
  return await provider.waitForTransaction(txHash, confirmations, timeout);
}

export async function sendERC20Token(tokenAddress, to, amount, decimals = 18) {
  const erc20Abi = [
    "function transfer(address to, uint256 amount) returns (bool)",
    "function balanceOf(address account) view returns (uint256)",
    "function decimals() view returns (uint8)",
  ];

  const contract = getContract(tokenAddress, erc20Abi, wallet);
  const parsedAmount = ethers.parseUnits(String(amount), decimals);
  const tx = await contract.transfer(to, parsedAmount);
  const receipt = await tx.wait(1);

  return {
    hash: tx.hash,
    receipt,
  };
}

export async function getERC20Balance(tokenAddress, address) {
  const erc20Abi = [
    "function balanceOf(address account) view returns (uint256)",
    "function decimals() view returns (uint8)",
  ];

  const contract = getContract(tokenAddress, erc20Abi, provider);
  const [balance, decimals] = await Promise.all([
    contract.balanceOf(address),
    contract.decimals(),
  ]);

  return {
    raw: balance.toString(),
    formatted: ethers.formatUnits(balance, decimals),
    decimals: Number(decimals),
  };
}

